  getListado(): void {

    this.listado = [];
    this.filteredItems = this.listado;
    this.init();

    this.loading = true;
    //this.showToast('info', 'Info!', 'Consultando...');
    
    var that = this;

    this.api_serv.getQuery(`usuarios/clientes/emisores`)
    .subscribe({
      next(data : any) {
        console.log(data);
        that.listado = data.clientes;
        that.filteredItems = that.listado; 
        that.init();  
        that.loading = false;   

      },
      error(msg) {
        console.log(msg);
        that.loading = false;
        that.tratarError(msg);
      }
    });

  }

  refreshTabla(){
    this.getListado();
  }


  ChangeStatus(obj){
    this.setStatus(obj);
  }

  setStatus(obj){

    let status_aux = null;

    if(!obj.status){
      status_aux = 0;
    }else if(obj.status){
      status_aux = 1;
    }

    this.loading = true;
    //this.showToast('info', 'Info!', 'Consultando...');
    
    var datos = {
      status : status_aux,
    };

    var that = this;

    this.api_serv.putQuery(`usuarios/status/${obj.id}`, datos)
    .subscribe({
      next(data : any) {
        console.log(data);

        that.loading = false;
        //that.showToast('success', 'Success!', data.message);      

      },
      error(msg) {
        console.log(msg);
        that.loading = false;
        that.tratarError(msg);
      }
    });
  }

