  guardar(): void {
    console.log( this.myForm );

    let password_valid = (this.myForm.value.password==this.myForm.value.password2)?true:false;
    let pass_valid = (this.myForm.value.pass==this.myForm.value.pass2)?true:false;

    if ( this.myForm.invalid || !password_valid || !this.myForm.value.zipcode_valid || !pass_valid) {

      if(this.myForm.get('email').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa tu email');
      }else if(this.myForm.get('telefono').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa tu teléfono');
      }else if(!password_valid){
        this.showToast('warning', 'Warning!', 'Los passwords de usuario son diferentes');
      }else if(this.myForm.get('color_a').invalid || 
         this.myForm.get('color_b').invalid || 
         this.myForm.get('color_c').invalid){
        this.showToast('warning', 'Warning!', 'Selecciona los colores');
      }else if(this.myForm.get('dominio').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa el nombre del subdominio');
      }else if(this.myForm.get('costo_factura').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa el costo de la factura');
      }

      else if(this.myForm.get('Rfc').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa tu Rfc');
      }else if(this.myForm.get('RazonSocial').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa tu Razón Social');
      }else if(this.myForm.get('RegimenFiscal').invalid){
        this.showToast('warning', 'Warning!', 'Selecciona tu Régimen Fiscal');
      }else if(this.myForm.get('CP').invalid){
        this.showToast('warning', 'Warning!', 'Ingresa el Código Postal de tu domicilio');
      }else if(!this.myForm.value.zipcode_valid){
        this.showToast('warning', 'Warning!', 'Código Postal no disponible en el catálogo');
      }else if(!pass_valid){
        this.showToast('warning', 'Warning!', 'Los passwords del certificado son diferentes');
      }else if(this.myForm.get('key').invalid){
        this.showToast('warning', 'Warning!', 'Adjunta tu Clave privada (.key)');
      }else if(this.myForm.get('cer').invalid){
        this.showToast('warning', 'Warning!', 'Adjunta tu Certificado (.cer)');
      }

      return Object.values( this.myForm.controls ).forEach( control => {
        
        if ( control instanceof FormGroup ) {
          Object.values( control.controls ).forEach( control => control.markAsTouched() );
        } else {
          control.markAsTouched();
        }
 
      });
     
    }else{

      if (this.accion == 0) {
        this.crear();
      }else if (this.accion == 1) {
        this.editar();
      }
      
    }
  }

