  async resizeImageWithFrame(file) {
    return new Promise((resolve) => {
      const reader = new FileReader();

      reader.onload = (e: any) => {
        const img = new Image();
        img.src = e.target.result;

        img.onload = () => {
          const canvas = document.createElement('canvas');
          const ctx = canvas.getContext('2d');

          const currentWidth = img.width;
          const currentHeight = img.height;
          const isSquare = currentWidth === currentHeight;

          let newWidth, newHeight;

          if (!isSquare) {
            newWidth = currentWidth > currentHeight ? 640 : Math.round((currentWidth * 640) / currentHeight);
            newHeight = currentHeight > currentWidth ? 640 : Math.round((currentHeight * 640) / currentWidth);
          } else {
            newWidth = newHeight = Math.min(currentWidth, 640);
          }

          canvas.width = isSquare ? currentWidth : 640;
          canvas.height = isSquare ? currentHeight : 640;

          const x = (640 - newWidth) / 2;
          const y = (640 - newHeight) / 2;
          ctx.drawImage(img, x, y, newWidth, newHeight);

          canvas.toBlob((blob) => {
            const lastModified = new Date().getTime();
            const type = 'image/png';

            const resizedFile = new File([blob], file.name, { type, lastModified });
            resolve(resizedFile);
          }, 'image/png');
        };
      };

      reader.readAsDataURL(file);
    });
  }


  extraerBase64 = async ($event: any) => new Promise((resolve, reject) => {
    try {
      const unsafeImg = window.URL.createObjectURL($event);
      const image = this.sanitizer.bypassSecurityTrustUrl(unsafeImg);
      const reader = new FileReader();
      reader.readAsDataURL($event);
      reader.onload = () => {
        resolve({
          base: reader.result
        });
      };
      reader.onerror = error => {
        resolve({
          base: null
        });
      };

    } catch (e) {
      return null;
    }
  })


